import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  // Simplest cases
  it.todo("should return empty array when given empty array");
  it.todo("should kill a single cell with 0 neighbors -- [(0,0)] -> []");

  // Rule 1: Underpopulation (live cell with < 2 neighbors dies)
  it.todo("Rule 1 Underpopulation: two adjacent cells each with 1 neighbor both die -- [(0,1),(1,1)] -> []");

  // Rule 2: Survival (live cell with 2 or 3 neighbors lives on)
  // Rule 4: Reproduction (dead cell with exactly 3 neighbors becomes alive)
  it.todo("Rule 2 Survival: center cell (1,1) with 3 live neighbors survives in T-shape -- [(0,2),(1,2),(2,2),(1,0)] next gen contains (1,1)");

  // Rule 3: Overpopulation (live cell with > 3 neighbors dies)
  it.todo("Rule 3 Overpopulation: center cell with 4 neighbors dies -- 8 surrounding cells make center die");

  // Rule 4: Reproduction explicit example
  it.todo("Rule 4 Reproduction: dead cell (1,1) with exactly 3 live neighbors becomes alive -- [(0,2),(1,2),(0,1)] -> contains (1,1)");

  // Pattern examples from spec
  it.todo("Blinker oscillator: vertical [(0,0),(0,1),(0,2)] becomes horizontal [(-1,1),(0,1),(1,1)]");
  it.todo("Block still life: [(0,0),(1,0),(0,1),(1,1)] stays unchanged");

  // Negative coordinates (constraint)
  it.todo("should handle negative coordinates -- blinker centered at origin includes (-1,1)");
});

